import { Agent, Subagent } from "@anthropic-ai/claude-agent-sdk";

// Create main agent
const mainAgent = new Agent({
  instructions: "You are the orchestrator. Delegate to subagents for specialized work."
});

// Create subagents
const researchAgent = new Subagent({
  instructions: "You are a research specialist. Gather information and summarize findings."
});

const codingAgent = new Subagent({
  instructions: "You are a coding specialist. Write, edit, and debug code."
});

// Delegate tasks
await mainAgent.delegate("Research this topic", researchAgent);
await mainAgent.delegate("Write the implementation", codingAgent);

import { Agent, Hooks } from "@anthropic-ai/claude-agent-sdk";

// Create hooks
const hooks = new Hooks({
  // Intercept before tool use
  preToolUse: async (input) => {
    console.log(`Tool ${input.toolName} will be called`);

    // Modify tool arguments
    return {
      ...input,
      arguments: { ...input.arguments, validated: true }
    };
  },

  // Intercept after tool use
  postToolUse: async (input) => {
    console.log(`Tool ${input.toolName} completed`);

    // Log result or modify
    return {
      ...input,
      result: { ...input.result, logged: true }
    };
  },

  // Intercept user prompt
  userPromptSubmit: async (input) => {
    console.log(`Received prompt: ${input.prompt}`);

    // Modify prompt before processing
    return {
      ...input,
      prompt: `Enhanced: ${input.prompt}`
    };
  }
});

// Create agent with hooks
const agent = new Agent({ hooks });

// Create subagent with security hooks
const secureAgent = new Subagent({
  instructions: "You are a coding specialist.",
  hooks: {
    preToolUse: async (input) => {
      // Validate tool arguments
      if (input.toolName === "write_file" && !input.arguments.path.startsWith("/safe/")) {
        throw new Error("Only write to safe directories");
      }
      return input;
    }
  }
});

// Main agent delegates to secure subagent
await mainAgent.delegate("Write code", secureAgent);
